def solve(history_level, ekg_finding, age, risk_factor_count, has_atherosclerotic_disease, troponin_ratio):
    # Step 1: Evaluate history score
    if history_level == 'Slightly suspicious':
        history_points = 0
    elif history_level == 'Moderately suspicious':
        history_points = 1
    elif history_level == 'Highly suspicious':
        history_points = 2
    else:
        raise ValueError("Invalid history_level")
    yield {
        "step_name": "evaluate_history_score",
        "step_description": "Map the patient's history suspicion level to points (0, 1, or 2).",
        "step_result": history_points,
        "unit": None
    }

    # Step 2: Evaluate EKG score
    if ekg_finding == 'Normal':
        ekg_points = 0
    elif ekg_finding == 'Non-specific repolarization disturbance':
        ekg_points = 1
    elif ekg_finding == 'Significant ST deviation':
        ekg_points = 2
    else:
        raise ValueError("Invalid ekg_finding")
    yield {
        "step_name": "evaluate_ekg_score",
        "step_description": "Map the patient's EKG finding to points (0, 1, or 2).",
        "step_result": ekg_points,
        "unit": None
    }

    # Step 3: Evaluate age score
    if age < 45:
        age_points = 0
    elif 45 <= age <= 64:
        age_points = 1
    else:  # age >= 65
        age_points = 2
    yield {
        "step_name": "evaluate_age_score",
        "step_description": "Assign points based on patient's age group (0-44:0, 45-64:1, >=65:2).",
        "step_result": age_points,
        "unit": None
    }

    # Step 4: Evaluate risk factor score
    if has_atherosclerotic_disease:
        risk_factor_points = 2
    else:
        if risk_factor_count == 0:
            risk_factor_points = 0
        elif 1 <= risk_factor_count <= 2:
            risk_factor_points = 1
        else:  # risk_factor_count >= 3
            risk_factor_points = 2
    yield {
        "step_name": "evaluate_risk_factor_score",
        "step_description": "Assign points based on risk factor count and atherosclerotic disease history.",
        "step_result": risk_factor_points,
        "unit": None
    }

    # Step 5: Evaluate troponin score
    if troponin_ratio <= 1:
        troponin_points = 0
    elif troponin_ratio <= 3:
        troponin_points = 1
    else:  # troponin_ratio > 3
        troponin_points = 2
    yield {
        "step_name": "evaluate_troponin_score",
        "step_description": "Assign points based on troponin ratio relative to normal upper limit.",
        "step_result": troponin_points,
        "unit": None
    }

    # Step 6: Calculate total HEART score
    total_heart_score = history_points + ekg_points + age_points + risk_factor_points + troponin_points
    yield {
        "step_name": "calculate_total_heart_score",
        "step_description": "Sum all individual component scores to obtain the total HEART score (0-10).",
        "step_result": total_heart_score,
        "unit": None
    }

    return total_heart_score
